import{_ as t,o as a,c as r,a4 as n}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"Color Change","description":"","frontmatter":{"title":"Color Change","phenomenon":"color-change"},"headers":[],"relativePath":"optical-phenomena/color-change.md","filePath":"optical-phenomena/color-change.md","lastUpdated":1784176423000}'),o={name:"optical-phenomena/color-change.md"};function i(l,e,d,h,s,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="color-change" tabindex="-1">Color Change <a class="header-anchor" href="#color-change" aria-label="Permalink to &quot;Color Change&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A few gems exhibit distinctly different hues under daylight (rich in blue-green) versus incandescent light (rich in red- yellow). The classic case is alexandrite, green in daylight and red in candlelight. Other Cr³⁺ / V³⁺-bearing species (sapphire, pyrope, certain spinels) can show similar effects. Mechanism: dual absorption bands of Cr³⁺ centered in the yellow and blue-green ranges.</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Cr³⁺ exhibits two principal absorption bands: one in the yellow (~580 nm) and one in the blue (~425 nm). Under daylight (blue- green rich), yellow light is transmitted → green appearance. Under incandescent light (red-yellow rich), yellow is absorbed and blue transmission dominates, combining with the red ambient to yield red/purple. The greater the green-vs-red contrast, the higher the alexandrite rating.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Daylight</th><th>Incandescent</th></tr></thead><tbody><tr><td>Alexandrite / 亚历山大石</td><td>green / teal</td><td>red / raspberry</td></tr><tr><td>Color-change Sapphire / 变色蓝宝</td><td>blue</td><td>purple</td></tr><tr><td>Color-change Garnet / 变色石榴石</td><td>blue-green</td><td>red-purple</td></tr><tr><td>Color-change Spinel / 变色尖晶石</td><td>blue</td><td>violet</td></tr><tr><td>Color-change Fluorite / 变色萤石</td><td>blue</td><td>purple</td></tr></tbody></table><p><em>See the <a href="./intro.html">optical phenomena overview</a>.</em></p>',8)])])}const g=t(o,[["render",i]]);export{m as __pageData,g as default};
